import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"白鸦流","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/九剑/白鸦流.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/九剑/白鸦流.md"}'),s={name:"4.资源分区/6.技艺及称号/武技类/白刃类/九剑/白鸦流.md"};function o(d,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"白鸦流",tabindex:"-1"},[p("白鸦流 "),r("a",{class:"header-anchor",href:"#白鸦流","aria-label":'Permalink to "白鸦流"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风022")])])],-1),n('<h1 id="白鸦流-1" tabindex="-1">白鸦流 <a class="header-anchor" href="#白鸦流-1" aria-label="Permalink to &quot;白鸦流&quot;">​</a></h1><p>白鸦流<br> “九剑”，九种武艺流派，此乃是传承自神秘世界的一系列玄奇的武术。<br> 白鸦流派的教条强调，集体合作的威力远超各自为战！遵循其教导的武者，大多充当战场中振奋军心的领袖！<br> 白鸦流的偏好武器是长剑，战斧，巨剑，战戟和战锤。</p><p>D级：<br> 领军冲锋（攻击技）<br> 价格：D+500<br> 动作：整轮动作<br> 距离：冲锋攻击<br> 目标：单体生物<br> 描述：你站在最前线，向敌阵冲去，保证你的友方单位能跟随你的脚步。<br> 白鸦派的教条是，掌握先机就可以掌握胜利。你知道用强力的冲锋领导攻击，更好的搅乱敌阵，并激励战场中的友方单位。<br> 效果：你向单个敌方目标发起冲锋攻击，此次冲锋攻击获得5DP士气加值与2个附加成功。</p><p>领导攻击（攻击技）<br> 价格：D+500<br> 动作：标准动作<br> 消耗：1点意志力<br> 距离：近战攻击<br> 目标：单体生物<br> 描述：你勇猛地向对手发动攻击。当你攻击时，你发出呐喊宣示胜利已在眼前。你的攻击可以激励周围的友方单位参与战斗，让他们重新焕发精力。<br> 效果：使用标准动作发动一次普通近战白刃攻击，若攻击命中，则你周围5米的队友，在对你击中的目标发起攻击时，可以获得5点士气加值，持续一轮。</p><p>C级：<br> 激励（架势技）<br> 价格：C+1000<br> 动作：迅捷动作<br> 消耗：2点意志力<br> 距离：自身为圆心<br> 范围：5米半径<br> 持续时间：一场景，或直到切换为下一种架势<br> 描述：你嘹亮的声音激励友方单位的意志力。只要你在战场中，你的友方单位在面对试图让他们意志屈服的效果时就更为坚强。<br> 白鸦派强调，军队只在有斗志的时候有存在的意义。在面对强大的敌军或是未曾预料到的困难时，即使是最有经验的战士如果缺乏意志力也没有任何的价值。当你启动激励架势时，你鼓励你的友方单位，蔑视敌方，有力地提高友方单位的精神和斗志。看着你所建立起来的榜样，即使在敌方想要瓦解你的友方单位的意志时，他们仍然能保持非常坚定。<br> 效果：当你启动这种架势后，范围内所有能听到你声音的友方单位在进行决心相关检定时都可以获得6DP的士气加值，与1点附加成功。</p><p>狮吼（强化技）<br> 价格：C+1000<br> 动作：迅捷动作<br> 消耗：2点意志力<br> 距离：自身为圆心<br> 范围：5米半径<br> 持续时间：一场景<br> 描述：你在击败对手后突然发出呐喊。被你作出的榜样所激励，你的友方单位用重新焕发的经历和决心进行战斗。<br> 当你击败对手后，你可以要求友方单位加紧攻击。他们的回应是用更更强的力量给敌军造成严重的压力。<br> 效果：每当你将一个势均力敌的敌方生物的生命值降到0时，可以通过迅捷动作发出胜利的呐喊，然后你和所有范围内的友方单位在接下来进行攻击检定时可以获得6DP的士气加值，与1点附加成功，该效果无法重复叠加。</p><p>军魂冲锋 （攻击技）<br> 价格：C+1000<br> 前提：此技能可由领军冲锋差价升级<br> 动作：整轮动作<br> 距离：近战攻击<br> 目标：单体生物<br> 描述：随着冲锋，你唤出胸中的愤怒，发出如雷霆般的声音。你不计后果的行动让对手感到震惊，并且让攻击拥有更强的力量。<br> 作为白鸦派的门徒，你知道如何把体内的能量集中成势不可挡的冲锋。在战斗中，你必须总是在最前方领军。<br> 效果：你向单个敌方目标发起冲锋攻击，此次冲锋攻击获得9DP士气加值与2个附加成功，冲锋有效距离取最大值计算。此外，在本次冲锋的移动行为结束后，即使对方离开了攻击范围，也可以按照脱离攻击范围一般进行冲锋攻击。</p><p>乱中求治<br> 价格：C+1000<br> 动作：标准动作<br> 消耗：1点意志力<br> 距离：近战攻击<br> 目标：单体生物<br> 描述：你发出严厉的命令，指挥同伴变换阵型。你的影响力让他们在还没意识到的时候就已经开始执行命令。你特别擅长运用你的影响力在战场指挥同伴。随着几声短暂的命令，你的同伴变换阵型，占据更有利的位置。<br> 效果：你发起一次近战攻击，本次攻击获得3DP士气加值。此外，在这次攻击后，所有以你为中心15米内的友方单位，都可以立即进行一次移动，此次移动不能超过20米。</p><p>B级：</p><p>胜利号角（强化技）<br> 价格：B+2000<br> 动作：迅捷动作<br> 距离：自身为圆心<br> 范围：15米半径<br> 持续时间：见下<br> 效果：每当你将一个势均力敌的敌方生物的生命值降到0时，可以通过迅捷动作吹响胜利的号角。在技艺发动后，15米范围内的所有范围内的友方单位都可以立即进行一次移动，此次移动不能超过70米。此外，在移动后，这些友方单位将获得5点洞察防御，以及基于洞察防御的1个防御附加成功，洞察防御与附加成功将持续一场景。</p><p>A级：<br> 军神冲锋（攻击技）<br> 价格：A+4000<br> 动作：整轮动作<br> 距离：近战攻击<br> 目标：冲锋路径上所有生物<br> 描述：随着震撼战场的呐喊，你领导着友方单位发起冲锋。被你的领导力感染，配合着你对战术的精通，你和你的友方单位组成了势不可挡浪潮。<br> 你是战场中的军神，让你可以领导友方单位发动即使是最有经验的战士也会感到恐惧和迷惑的攻击。在你的指挥下，你们的力量远比各自为战加起来要大。<br> 效果：<br> 你向单个敌方目标发起冲锋，本次冲锋将对此次冲锋路径上的所有目标都造成两次攻击。<br> 此外，这两次攻击将获得15DP士气加值，被军神冲锋攻击命中的敌方目标，会被无与伦比的气魄震撼得动弹不得，需要使用意志额外进行一次豁免，DC为伤害出目，否则将陷入A级心灵来源的震慑效果。特殊的是，本轮内处于你15米范围内的其他友方单位在攻击时同样可以享受这些攻击检定上的士气加值，以及在攻击命中后附带的额外震慑效果。</p><p>白鸦战术（强化技）<br> 价格：A+4000<br> 动作：迅捷动作<br> 距离：15+传奇决心*20米<br> 目标：所有友方单位<br> 描述：你可以激励友方单位发挥出武艺的神髓。随着几声简洁的命令，你诱使他们抓住机会，击退对手。<br> 你对战术的知识可以帮助友方单位发动攻击，以及观察，预测，和反击对手的攻击。在混乱的战斗中，你可以维持紧密合作所必须的秩序。<br> 效果：<br> 当你发动这种技艺后，选择在范围内的所有友方单位。他们的先攻检定结果立即提升你的先攻数值*1点，持续一个场景，每个友方单位以此方式提升的先攻值不可超过40点。<br> 如果他在此轮内还没有行动过，他的先攻顺位首先改变，然后可以按照改变过的先攻顺位行动。<br> 如果他在此轮已经行动过，那么他可以再次行动一轮，然后如同透支了一般，失去他下一轮的所有动作。<br> 这个技艺每场景只能使用一次。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const f=e(s,[["render",o]]);export{D as __pageData,f as default};
